    def add_plugin(self, name: str, config: Optional[dict] = None,
                   service_name_or_id: Optional[str] = None,
                   route_name_or_id: Optional[str] = None,
                   consumer_name_or_id: Optional[str] = None,
                   enabled: bool = True, tags: Optional[list] = None) -> dict:
        scope = "global"
        if service_name_or_id:
            scope = f"service:{service_name_or_id}"
        elif route_name_or_id:
            scope = f"route:{route_name_or_id}"
        print(f"Adding plugin: {name} (scope: {scope})")

        data = {
            "name": name,
            "enabled": enabled,
        }
        if config:
            data["config"] = config
        if service_name_or_id:
            data["service"] = {"name": service_name_or_id} if not self._is_uuid(service_name_or_id) else {"id": service_name_or_id}
        if route_name_or_id:
            data["route"] = {"name": route_name_or_id} if not self._is_uuid(route_name_or_id) else {"id": route_name_or_id}
        if consumer_name_or_id:
            data["consumer"] = {"username": consumer_name_or_id} if not self._is_uuid(consumer_name_or_id) else {"id": consumer_name_or_id}
        if tags:
            data["tags"] = tags

        result = self._request("POST", "/plugins", data)
        print(f"  Plugin '{name}' added (id: {result.get('id', 'N/A')})")
        return result

    def list_plugins(self) -> dict:
        return self._request("GET", "/plugins")

