        print(f"Creating consumer: {username}")
        data = {"username": username}
        if custom_id:
            data["custom_id"] = custom_id
        if tags:
            data["tags"] = tags
        result = self._request("POST", "/consumers", data)
        print(f"  Consumer '{username}' created (id: {result.get('id', 'N/A')})")
        return result

