def cleanup_infrastructure(kong: KongAdminClient):
    """Remove all configured resources (for testing/reset purposes)."""
    print("\n[CLEANUP] Removing all Kong configuration...")

    # Delete plugins first
    plugins = kong.list_plugins()
    for plugin in plugins.get("data", []):
        kong.delete_plugin(plugin["id"])

    # Delete routes
    routes = kong.list_routes()
    for route in routes.get("data", []):
        kong.delete_route(route["id"])

    # Delete services
    services = kong.list_services()
    for service in services.get("data", []):
        kong.delete_service(service["id"])

    # Delete upstreams (targets are deleted automatically)
    upstreams = kong.list_upstreams()
    for upstream in upstreams.get("data", []):
        kong.delete_upstream(upstream["id"])

    print("[CLEANUP] Done.")


def load_config_from_file(kong: KongAdminClient, config_path: str):
    """Load and apply configuration from a JSON file."""
    print(f"Loading configuration from: {config_path}")
    with open(config_path, "r") as f:
        config = json.load(f)

    for upstream in config.get("upstreams", []):
        targets = upstream.pop("targets", [])
        kong.create_upstream(**upstream)
        for target in targets:
            kong.add_target(upstream["name"], **target)

    for service in config.get("services", []):
        kong.create_service(**service)

    for route in config.get("routes", []):
        kong.create_route(**route)

    for plugin in config.get("plugins", []):
        kong.add_plugin(**plugin)

    for consumer in config.get("consumers", []):
        credentials = consumer.pop("credentials", {})
        kong.create_consumer(**consumer)
        for key in credentials.get("key_auth", []):
            kong.add_key_auth(consumer["username"], key=key)

    print("Configuration loaded successfully.")


def export_config(kong: KongAdminClient, output_path: str = "kong_export.json"):
    """Export current Kong configuration to a JSON file."""
    print(f"Exporting configuration to: {output_path}")
    config = {
        "exported_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
        "services": kong.list_services().get("data", []),
        "routes": kong.list_routes().get("data", []),
        "upstreams": kong.list_upstreams().get("data", []),
        "plugins": kong.list_plugins().get("data", []),
        "consumers": kong.list_consumers().get("data", []),
    }

    # Add targets for each upstream
    for upstream in config["upstreams"]:
        targets = kong.list_targets(upstream["id"])
        upstream["targets"] = targets.get("data", [])

    with open(output_path, "w") as f:
        json.dump(config, f, indent=2, default=str)

    print(f"Configuration exported to {output_path}")


if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(
        description="Kong API Gateway Infrastructure Automation",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  python kong_configurator.py --configure
  python kong_configurator.py --cleanup
  python kong_configurator.py --export --output kong_backup.json
  python kong_configurator.py --load-config config.json
  python kong_configurator.py --admin-url http://kong-admin:8001 --configure
        """,
    )
    parser.add_argument(
        "--admin-url",
        default="http://localhost:8001",
        help="Kong Admin API URL (default: http://localhost:8001)",
    )
    parser.add_argument(
        "--configure",
        action="store_true",
        help="Apply sample infrastructure configuration",
    )
    parser.add_argument(
        "--cleanup",
        action="store_true",
        help="Remove all Kong configuration",
    )
    parser.add_argument(
        "--export",
        action="store_true",
        help="Export current configuration to JSON",
    )
    parser.add_argument(
        "--output",
        default="kong_export.json",
        help="Output file for export (default: kong_export.json)",
    )
    parser.add_argument(
        "--load-config",
        type=str,
        help="Load configuration from a JSON file",
    )
    parser.add_argument(
        "--status",
        action="store_true",
        help="Show Kong node status",
    )

    args = parser.parse_args()

    kong_client = KongAdminClient(admin_url=args.admin_url)

    if args.status:
        if kong_client.health_check():
            info = kong_client.get_node_info()
            status = kong_client.get_status()
            print(f"Kong Version: {info.get('version', 'unknown')}")
            print(f"Node ID: {info.get('node_id', 'unknown')}")
            print(f"Hostname: {info.get('hostname', 'unknown')}")
            print(f"Database: {status.get('database', {}).get('reachable', False)}")
            server_status = status.get("server", {})
            print(f"Connections Active: {server_status.get('connections_active', 'N/A')}")
            print(f"Connections Accepted: {server_status.get('connections_accepted', 'N/A')}")
            print(f"Total Requests: {server_status.get('total_requests', 'N/A')}")
        else:
            print("[ERROR] Kong Admin API is not reachable")
            sys.exit(1)

    elif args.cleanup:
        cleanup_infrastructure(kong_client)

    elif args.export:
        export_config(kong_client, args.output)

    elif args.load_config:
        load_config_from_file(kong_client, args.load_config)

    elif args.configure:
        configure_sample_infrastructure(kong_client)

    else:
        parser.print_help()